import React, { useState, useEffect, useCallback } from "react";
import "./DisplayRows.css";

const ParameterDisplay = ({ parameters: initialParameters, isActive, onPageChange, onFocusChange, activeFocus, setAutoModeExternal, currentPage }) => {
  var UPDATE_INTERVAL_MS = 200;
  var ITEMS_PER_PAGE = 4;
  var SKIP_COUNT = 6;

  // State to hold the live fetched data
  const [parameters, setParameters] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const [autoMode, setAutoMode] = useState(false);

  // Integrated Fetch Logic
  const fetchParameters = useCallback(function() {
    var cacheBuster = new Date().getTime();

    fetch('/parameters.json?t=' + cacheBuster)
      .then(function(response) {
        if (!response.ok) {
          throw new Error('HTTP error! status: ' + response.status);
        }
        return response.json();
      })
      .then(function(jsonArray) {
        // Handle Metadata
        const pageData = jsonArray.find(function(obj) { return obj.page !== undefined; });
        if (pageData && onPageChange) onPageChange(pageData.page);

        const focusData = jsonArray.find(function(obj) { return obj.focus !== undefined; });
        if (focusData && onFocusChange) onFocusChange(focusData.focus);

        const autoModeEntry = jsonArray.find(function(obj) { return obj.autoMode !== undefined; });
        if (autoModeEntry !== undefined) {
          setAutoMode(autoModeEntry.autoMode);
          setAutoModeExternal(autoModeEntry.autoMode);
        }

        var updatedData = jsonArray.map(function(p) {
          return {
            id: p.id,
            name: p.name,
            unit: p.unit,
            value: p.value || '---'
          };
        });

        setParameters(updatedData);
        setIsLoading(false);
        setError(null);
      })
      .catch(function(e) {
        console.error("CONSOLE: Failed to fetch parameters:", e);
        setError(e.message);
        setIsLoading(false);
      });
  }, [onPageChange, onFocusChange, setAutoModeExternal]);

  useEffect(function() {
    fetchParameters();
    var intervalId = setInterval(fetchParameters, UPDATE_INTERVAL_MS);
    return function() {
      clearInterval(intervalId);
    };
  }, [fetchParameters]);

  if (autoMode) {
    return (
      <div className="parameter-rows-wrapper">
        <div className="autonomous-mode-overlay"><h2>AUTONOMOUS MODE ACTIVE</h2></div>
      </div>
    );
  }

  // Logic for Pagination and Focus
  const page = parseInt(currentPage || 1, 10);
  const focus = parseInt(activeFocus || 1, 10); // 1, 2, 3, or 4

  // Formula: 6 + 4 * (page - 1) + focus
  const targetGlobalIndex = SKIP_COUNT + (ITEMS_PER_PAGE * (page - 1)) + focus;

  // Calculate slice for display
  const startIndex = SKIP_COUNT + ((page - 1) * ITEMS_PER_PAGE);
  const endIndex = startIndex + ITEMS_PER_PAGE;

  // Filter out metadata and slice
  const displayList = parameters.filter(p => p.id !== undefined);
  const paginatedParameters = displayList.slice(startIndex, endIndex);

  return (
    <div className="parameter-rows-wrapper">
      {paginatedParameters.map(function(param, index) {
        // currentItemGlobalIndex calculates the absolute position in the array
        // We use index + 1 because 'focus' is 1-based
        const currentItemGlobalIndex = startIndex + (index);
        const isFocused = (currentItemGlobalIndex === targetGlobalIndex);

        return (
          <div key={param.id || currentItemGlobalIndex} className={"parameter-row " + (isFocused ? "focused" : "")}>
            <div className="parameter-label">{param.name}</div>
            <div className="parameter-value">
              {param.value} {param.unit}
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default ParameterDisplay;
